export interface BridgedHttpClientOptions {
  baseUrl: string;
  orgId: string;
  apiKey?: string;
  /** OIDC-exchanged BridgedAI JWT (Bearer auth). Mutually exclusive with apiKey for auth header selection. */
  accessToken?: string;
  timeoutMs?: number;
  preferAuthorizationApiKey?: boolean;
}

export interface JsonRequestOptions {
  method: 'GET' | 'POST';
  path: string;
  body?: unknown;
  allowRetry?: boolean;
}

export class BridgedApiError extends Error {
  readonly status: number;
  readonly code?: string;
  readonly detail?: string;
  readonly bodySnippet: string;

  constructor(opts: { status: number; message: string; code?: string; detail?: string; bodySnippet?: string }) {
    super(opts.message);
    this.name = 'BridgedApiError';
    this.status = opts.status;
    this.code = opts.code;
    this.detail = opts.detail;
    this.bodySnippet = opts.bodySnippet ?? '';
  }
}

function problemMessage(status: number, body: unknown, rawText: string): { msg: string; code?: string; detail?: string } {
  if (body && typeof body === 'object') {
    const o = body as Record<string, unknown>;
    const detail = typeof o.detail === 'string' ? o.detail : typeof o.message === 'string' ? o.message : undefined;
    const title = typeof o.title === 'string' ? o.title : undefined;
    const code = typeof o.code === 'string' ? o.code : typeof o.error === 'string' ? o.error : undefined;
    const msg = [title, detail].filter(Boolean).join(': ') || `HTTP ${status}`;
    return { msg, code, detail };
  }
  const t = rawText.length > 2000 ? `${rawText.slice(0, 2000)}…` : rawText;
  return { msg: t || `HTTP ${status}` };
}

export class BridgedHttpClient {
  readonly baseUrl: string;
  private readonly apiKey: string;
  private readonly accessToken: string;
  private readonly orgId: string;
  private readonly timeoutMs: number;
  private readonly preferAuthorizationApiKey: boolean;

  constructor(opts: BridgedHttpClientOptions) {
    this.baseUrl = normalizeBaseUrl(opts.baseUrl);
    let apiKey = String(opts.apiKey ?? '').trim();
    let accessToken = String(opts.accessToken ?? '').trim();
    if (apiKey.length > MAX_BRIDGED_CREDENTIAL_LENGTH || accessToken.length > MAX_BRIDGED_CREDENTIAL_LENGTH) {
      throw new Error('BridgedAI credential exceeds maximum allowed length');
    }
    if (accessToken && isBridgedApiKey(accessToken)) {
      apiKey = accessToken;
      accessToken = '';
    }
    this.apiKey = apiKey;
    this.accessToken = accessToken;
    this.orgId = String(opts.orgId ?? '').trim();
    this.timeoutMs = opts.timeoutMs ?? 30_000;
    this.preferAuthorizationApiKey = opts.preferAuthorizationApiKey ?? false;
    if (!this.apiKey && !this.accessToken) {
      throw new Error('Missing BridgedAI credentials (apiKey or accessToken required)');
    }
    if (!this.orgId) throw new Error('Missing BridgedAI organization id');
    if (!isValidBridgedOrgId(this.orgId)) {
      throw new Error('Invalid BridgedAI organization id format (expected org_<uuid>)');
    }
  }

  /** Credential used for log redaction (never logged itself). */
  private redactionSecret(): string {
    return this.accessToken || this.apiKey;
  }

  private authHeaders(): Record<string, string> {
    if (this.accessToken) {
      return {
        Authorization: `Bearer ${this.accessToken}`,
        'x-org-id': this.orgId,
      };
    }
    if (this.preferAuthorizationApiKey) {
      return {
        Authorization: `ApiKey ${this.apiKey}`,
        'x-org-id': this.orgId,
      };
    }
    return {
      'x-api-key': this.apiKey,
      'x-org-id': this.orgId,
    };
  }

  async requestJson<T>(opts: JsonRequestOptions): Promise<T> {
    const url = `${this.baseUrl}${opts.path.startsWith('/') ? opts.path : `/${opts.path}`}`;
    const allowRetry = opts.allowRetry ?? opts.method === 'GET';

    return withRetry(
      async () => {
        const controller = new AbortController();
        const timer = setTimeout(() => controller.abort(), this.timeoutMs);
        try {
          const headers: Record<string, string> = {
            accept: 'application/json',
            ...this.authHeaders(),
          };
          const init: RequestInit = { method: opts.method, headers, signal: controller.signal };
          if (opts.body !== undefined && opts.method === 'POST') {
            headers['content-type'] = 'application/json';
            init.body = JSON.stringify(opts.body);
          }

          const res = await fetch(url, init);
          const text = await res.text();
          let parsed: unknown = undefined;
          if (text) {
            try {
              parsed = JSON.parse(text) as unknown;
            } catch {
              parsed = { raw: text };
            }
          }

          if (res.ok) return parsed as T;

          const { msg, code, detail } = problemMessage(res.status, parsed, text);
          const secret = this.redactionSecret();
          const snippet = redactSecrets(text.slice(0, 800), secret);
          let userMsg = redactSecrets(msg, secret);
          if (res.status === 422) {
            userMsg += ' (Unprocessable entity — verify JSON body matches the public CI API contract.)';
          }

          const retryable = res.status === 502 || res.status === 503 || res.status === 504;
          if (allowRetry && retryable) {
            throw Object.assign(new BridgedApiError({
              status: res.status,
              message: `BridgedAI API ${res.status}: ${userMsg}`,
              code,
              detail,
              bodySnippet: snippet,
            }), { retryable: true });
          }

          throw new BridgedApiError({
            status: res.status,
            message: `BridgedAI API ${res.status}: ${userMsg}`,
            code,
            detail,
            bodySnippet: snippet,
          });
        } catch (e) {
          if (e instanceof BridgedApiError) throw e;
          const aborted = e instanceof Error && e.name === 'AbortError';
          if (aborted) {
            throw new BridgedApiError({
              status: 0,
              message: `BridgedAI request timed out after ${this.timeoutMs}ms (${opts.method} ${opts.path})`,
            });
          }
          throw e;
        } finally {
          clearTimeout(timer);
        }
      },
      {
        maxAttempts: allowRetry ? 3 : 1,
        isRetryable: (e) => {
          if (e && typeof e === 'object' && 'retryable' in e) return !!(e as { retryable: boolean }).retryable;
          if (e instanceof BridgedApiError) return e.status === 502 || e.status === 503 || e.status === 504;
          return false;
        },
      },
    );
  }
}

