/** CI resolve: always send workflowRunId and commitSha so the API can match legacy builds. */
export async function resolveBuildForCi(
  client: BridgedHttpClient,
  params: {
    orgId: string;
    repoFullName: string;
    workflowRunId?: string;
    commitSha?: string;
    branch?: string;
  },
): Promise<BuildResolveResponse> {
  return resolveBuild(client, {
    orgId: params.orgId,
    repoFullName: params.repoFullName,
    workflowRunId: params.workflowRunId,
    commitSha: params.commitSha,
    branch: params.branch,
  });
}

